// Aggregate per-question Speechace results to 5 dimensions.
// Per spec v1.1 §Node 6: per-question dimension averages, with rubric weighting.
// Speechace v9 spontaneous_speech returns speech_score per call.
//
// $input.all() returns the accumulated results from the SplitInBatches loop.
// Each item is one Speechace API response.

const items = $input.all();
const round1 = (n) => typeof n === 'number' ? Math.round(n * 10) / 10 : 0;
const toFive = (s100) => Math.max(0, Math.min(5, (s100 || 0) / 20));
const toCefr = (s) => s >= 90 ? 'C1' : s >= 80 ? 'B2+' : s >= 70 ? 'B2' : s >= 60 ? 'B1+' : s >= 50 ? 'B1' : 'A2+';

// Collect per-dimension scores across all questions
const pron = [], flu = [], gra = [], voc = [], coh = [];
const transcripts = [];
const flags = [];
let failures = 0;

for (const item of items) {
  const sp = item.json?.speech_score || item.json || {};
  if (!sp || sp.status === 'error') {
    failures++;
    continue;
  }
  // May 5 fix: ALL 5 dims live under speech_score.speechace_score, not at the top
  // level of speech_score. Verified by inspecting live exec 37590 against real
  // recording. The earlier paths (sp.fluency.score / sp.grammar.score / etc.) all
  // returned undefined → those 4 dims were silently 0. Speechace's /speech endpoint
  // returns: speechace_score: { pronunciation, fluency, grammar, coherence, vocab, overall }.
  const ss = sp.speechace_score || {};
  if (typeof ss.pronunciation === 'number') pron.push(ss.pronunciation);
  if (typeof ss.fluency === 'number') flu.push(ss.fluency);
  if (typeof ss.grammar === 'number') gra.push(ss.grammar);
  if (typeof ss.vocab === 'number') voc.push(ss.vocab);
  if (typeof ss.coherence === 'number') coh.push(ss.coherence);
  if (sp.text || sp.transcript) transcripts.push(sp.text || sp.transcript);
}

// Per spec v1.2 §4: ≤2 failures tolerated; ≥3 → flag audio_quality_poor
if (failures >= 3) flags.push('audio_quality_poor');

const avg = (a) => a.length ? a.reduce((x,y)=>x+y, 0) / a.length : 0;
const dim = (a) => ({ score: round1(toFive(avg(a))), cefr: toCefr(avg(a)) });

const speechace_5dim = {
  pronunciation: dim(pron),
  fluency:       dim(flu),
  grammar:       dim(gra),
  vocabulary:    dim(voc),
  coherence:     dim(coh),
};

// Build a transcript dictionary keyed by question_id (best-effort)
const ctx = $('Validate Contract 1 Payload').item.json;
const audio_files = ctx.recording?.audio_files || [];
const transcript_map = {};
for (let i = 0; i < items.length; i++) {
  const af = audio_files[i] || {};
  const qid = (af.question_id || ('q' + (i+1))).toLowerCase();
  transcript_map[qid] = transcripts[i] || '';
}

return [{ json: {
  ...ctx,
  speechace_5dim,
  speechace_transcripts: transcript_map,
  speechace_flags: flags,
  speechace_failure_count: failures,
} }];

// Parse Anthropic response → comprehension JSON; apply rubric weights → unified scorecard.
// Per config/rubric_thresholds.json (locked Apr 24): weights pron 0.25 / comp 0.20 / flu 0.20 /
// gra 0.15 / coh 0.10 / voc 0.10. Tier verdicts: T1 20/16, T2 23/19, T3 25/21.

const resp = $json;
const txt = (resp.content && resp.content[0] && resp.content[0].text) ? resp.content[0].text : '{}';

let comp;
try {
  const cleaned = txt.replace(/^\s*\u0060\u0060\u0060json\s*/i, '').replace(/\s*\u0060\u0060\u0060\s*$/i, '').trim();
  comp = JSON.parse(cleaned);
} catch (e) {
  // B1/3.0 fallback per spec v1.1 §Node 7
  comp = {
    schema_version: '1.1',
    model: 'claude-sonnet-4-6',
    call_timestamp: new Date().toISOString(),
    candidate_ref: { workable_id: '', session_id: '' },
    comprehension: { cefr: 'B1', numeric_score: 3.0, paraphrase_accuracy: 'partial', instruction_following: 'adequate', relevance: 'partial' },
    qualitative: { claude_note: 'Comprehension parse failed; B1/3.0 fallback per spec v1.1 §Node 7.' },
    interview_observations: [],
    risk_indicators: null,
    flags: ['comprehension_parse_fallback', 'audio_quality_poor'],
    cost_usd: 0,
  };
}

// May 5 fix: Sonnet has been observed hallucinating model name + call_timestamp
// inside the JSON it returns (e.g. {"model":"claude-opus-4-5","call_timestamp":
// "2025-07-15T00:00:00Z"} despite actually being claude-sonnet-4-6 called now).
// Stamp these server-side so the scorecard always reflects ground truth.
comp.model = 'claude-sonnet-4-6';
comp.call_timestamp = new Date().toISOString();
comp.schema_version = '1.1';

const ctx = $('Aggregate Speechace 5-dim').item.json;
const sp = ctx.speechace_5dim;
const tier = ctx.candidate.tier;

const weights = { pronunciation: 0.25, comprehension: 0.20, fluency: 0.20, grammar: 0.15, coherence: 0.10, vocabulary: 0.10 };
const round1 = (n) => Math.round(n * 10) / 10;

const dimEntry = (raw_0_5, cefr, weight) => ({
  score: round1(raw_0_5 * weight * 6),
  cefr,
  weight,
  max: round1(weight * 30),
});

// May 5 fix: clamp comprehension to 0-5 range. Sonnet has been observed returning
// numeric_score on a 0-100 scale (e.g. 72) despite the prompt asking for 0-5,
// which produced impossible scorecard values like comprehension 86.4 / 6.
// Defensive normalization: anything > 5 is treated as 0-100 and divided by 20.
const normalizeCompTo5 = (raw) => {
  const n = Number(raw) || 0;
  if (n <= 5) return Math.max(0, n);
  if (n <= 100) return n / 20;
  return 5;
};
const compRaw5 = normalizeCompTo5(comp.comprehension?.numeric_score);

const dims = {
  pronunciation: dimEntry(sp.pronunciation.score, sp.pronunciation.cefr, weights.pronunciation),
  comprehension: dimEntry(compRaw5, comp.comprehension?.cefr || 'B1', weights.comprehension),
  fluency:       dimEntry(sp.fluency.score, sp.fluency.cefr, weights.fluency),
  grammar:       dimEntry(sp.grammar.score, sp.grammar.cefr, weights.grammar),
  coherence:     dimEntry(sp.coherence.score, sp.coherence.cefr, weights.coherence),
  vocabulary:    dimEntry(sp.vocabulary.score, sp.vocabulary.cefr, weights.vocabulary),
};

let overall = 0;
for (const k of Object.keys(dims)) overall += dims[k].score;
overall = round1(overall);

const thresholds = { 1: { pass: 20, borderline: 16 }, 2: { pass: 23, borderline: 19 }, 3: { pass: 25, borderline: 21 } };
const t = thresholds[tier] || thresholds[1];
const verdict = overall >= t.pass ? 'PASS' : overall >= t.borderline ? 'BORDERLINE' : 'FAIL';

const dimEntries = Object.entries(dims);
dimEntries.sort((a, b) => (b[1].score / b[1].max) - (a[1].score / a[1].max));
const strongest = dimEntries[0][0];
const weakest = dimEntries[dimEntries.length - 1][0];

const recommendation = verdict === 'PASS'
  ? { action: 'AUTO_ADVANCE', next_stage: 'Preliminary Assessments', rationale_short: 'Advance.' }
  : verdict === 'BORDERLINE'
  ? { action: 'RECRUITER_REVIEW', next_stage: null, rationale_short: 'Held for recruiter review — BORDERLINE no longer auto-advances (SV TA, June 2026).' }
  : { action: 'AUTO_REJECT', next_stage: null, rationale_short: 'Do not advance.' };

const grade = verdict === 'PASS' ? 2 : verdict === 'BORDERLINE' ? 1 : 0;

// Flag merging — Speechace + Claude flags
const allFlags = [...(ctx.speechace_flags || []), ...(comp.flags || [])];

// Durable recording link (best-effort). Points at the landing-page viewer
// endpoint which re-signs the Supabase audio on each load, so the link never
// expires. Date is the upload-date folder parsed from the audio path
// (sessions/{date}/{session}/{qid}.webm). Omitted if no session_id — the
// renderer guards on sc.recording_url presence.
const _rec = ctx.recording || {};
const _recSession = _rec.session_id || '';
const _recPath = (_rec.audio_files && _rec.audio_files[0] && (_rec.audio_files[0].path || _rec.audio_files[0].read_url)) || '';
const _recDate = (_recPath.split('/')[1]) || '';
const recording_url = _recSession
  ? ('https://client-scale-virtually-landing-page.vercel.app/api/recording?session=' + encodeURIComponent(_recSession) + (_recDate ? '&d=' + encodeURIComponent(_recDate) : ''))
  : null;

const scorecard = {
  schema_version: '1.0',
  generated_at: new Date().toISOString(),
  workflow_run_id: 'wfc_' + Date.now(),
  recording_url,
  candidate: { workable_id: ctx.candidate.workable_id },
  role: { role_code: ctx.candidate.role_type, tier, tier_label: 'Tier ' + tier },
  scores: {
    overall,
    overall_max: 30,
    cefr_overall: comp.comprehension.cefr || 'B1',
    verdict,
    dimensions: dims,
  },
  qualitative: {
    claude_note: comp.qualitative?.claude_note || '',
    strongest_dimension: strongest,
    weakest_dimension: weakest,
    flags: [...new Set(allFlags)],
    interview_observations: Array.isArray(comp.interview_observations) ? comp.interview_observations : [],
    risk_indicators: comp.risk_indicators || null,
  },
  recommendation,
};

// Pull through candidate metadata (first_name/role_label/email) for downstream Workable nodes
const first_name = ctx.candidate.firstname || ctx.candidate.first_name || '';
const role_label = ctx.candidate.role_label || ctx.candidate.role_type || '';

return [{ json: { ...ctx, scorecard, verdict, grade, comprehension: comp, first_name, role_label, candidate_id: ctx.candidate.workable_id } }];

// Render scorecard — full v1.5 mirror of src/scorecard_renderer.js (LOCKED).
// v1.5 (2026-06-12): terse FLAGS block retired → INTERVIEW OBSERVATIONS +
// RISK INDICATORS + readable NOTES + optional RECORDING line.
const sc = $json.scorecard;
const LINE_WIDTH = 60;
const DIVIDER = '━'.repeat(56);
const VERDICT_ICON = { PASS: '✅', BORDERLINE: '⚠', FAIL: '✗' };
const DIMENSION_ORDER = [
  ['pronunciation', 'Pronunciation'],
  ['comprehension', 'Comprehension'],
  ['fluency',       'Fluency'],
  ['grammar',       'Grammar'],
  ['coherence',     'Coherence'],
  ['vocabulary',    'Vocabulary'],
];
const CEFR_BAND = { 'C2':'strong','C1':'strong','B2+':'on_target','B2':'on_target','B1+':'below','B1':'below','A2+':'floor','A2':'floor','A1+':'floor','A1':'floor' };
const BAND_LABEL = { strong:'✓ strong', on_target:'✓ on target', below:'⚠ below', floor:'✗ floor' };
const FLAG_LABELS = {
  audio_quality_poor:  'audio_quality_poor — signal noise affected scoring',
  short_responses:     'short_responses — 3 of 7 answers under target length',
  off_topic_q3:        'off_topic_q3 — paraphrase task not followed as asked',
  language_switching:  'language_switching — candidate switched to Tagalog in Q4',
};
function dimensionDelta(dimKey, dim, strongestKey, weakestKey, verdict) {
  const band = CEFR_BAND[dim.cefr] || 'floor';
  const base = BAND_LABEL[band];
  if (dimKey === strongestKey && verdict !== 'FAIL') return base + ' (top)';
  if (dimKey === weakestKey)   return base + ' (low)';
  return base;
}
function wrap(text, width) {
  const words = (text || '').split(/\s+/);
  const lines = []; let cur = '';
  for (const w of words) {
    if (!cur) { cur = w; continue; }
    if ((cur + ' ' + w).length <= width) cur += ' ' + w;
    else { lines.push(cur); cur = w; }
  }
  if (cur) lines.push(cur);
  return lines;
}
function wrapWithPrefix(prefix, text, totalWidth) {
  const firstLineWidth = totalWidth - prefix.length;
  const words = (text || '').split(/\s+/);
  const lines = []; let cur = ''; let first = true;
  for (const w of words) {
    const limit = first ? firstLineWidth : totalWidth;
    if (!cur) cur = w;
    else if ((cur + ' ' + w).length <= limit) cur += ' ' + w;
    else { lines.push(first ? prefix + cur : cur); cur = w; first = false; }
  }
  if (cur) lines.push(first ? prefix + cur : cur);
  return lines;
}
function formatTimestamp(iso) {
  const d = new Date(iso);
  const pad = (n) => String(n).padStart(2, '0');
  return d.getUTCFullYear() + '-' + pad(d.getUTCMonth()+1) + '-' + pad(d.getUTCDate()) + ' ' + pad(d.getUTCHours()) + ':' + pad(d.getUTCMinutes()) + ' UTC';
}

const lines = [];
// HEADER
lines.push('🤖 AI SCREENING COMPLETE  •  ' + formatTimestamp(sc.generated_at));
lines.push('');
// VERDICT BANNER
const icon = VERDICT_ICON[sc.scores.verdict] || '';
const scoreStr = 'Overall ' + sc.scores.overall.toFixed(1) + ' / ' + sc.scores.overall_max;
const cefrStr  = 'CEFR ' + sc.scores.cefr_overall;
lines.push(icon + ' ' + sc.scores.verdict + ' — ' + scoreStr + ' · ' + cefrStr);
lines.push('');
// SUMMARY RECOMMENDATION
const recText = sc.recommendation.rationale_short || sc.recommendation.rationale || '';
wrapWithPrefix('Recommendation: ', recText, LINE_WIDTH).forEach(l => lines.push(l));
lines.push('');
// DIVIDER → DETAILED BLOCK
lines.push(DIVIDER);
lines.push('');
// DIMENSION BREAKDOWN
lines.push('DIMENSION BREAKDOWN');
lines.push('');
const strongest = sc.qualitative.strongest_dimension;
const weakest   = sc.qualitative.weakest_dimension;
for (const [key, label] of DIMENSION_ORDER) {
  const d = sc.scores.dimensions[key];
  if (!d) continue;
  const scoreCell = d.score.toFixed(1) + ' / ' + d.max.toFixed(1);
  const deltaCell = dimensionDelta(key, d, strongest, weakest, sc.scores.verdict);
  lines.push(label + ': ' + scoreCell + ' · ' + d.cefr + ' · ' + deltaCell);
}
lines.push('');
// NARRATIVE
lines.push('NARRATIVE');
lines.push('');
wrap(sc.qualitative.claude_note || '', LINE_WIDTH).forEach(l => lines.push(l));
lines.push('');
// INTERVIEW OBSERVATIONS (Contract 3 v1.1) — per-question readable notes.
const observations = sc.qualitative.interview_observations;
if (Array.isArray(observations) && observations.length > 0) {
  lines.push('INTERVIEW OBSERVATIONS');
  lines.push('');
  observations.forEach(o => {
    const qid = (o.question_id || '').toUpperCase();
    const head = qid ? (qid + ' — ' + o.label + ': ') : (o.label + ': ');
    wrapWithPrefix(head, o.observation || '', LINE_WIDTH).forEach(l => lines.push(l));
  });
  lines.push('');
}
// RISK INDICATORS (Contract 3 v1.1) — advisory recruiter signals.
const risk = sc.qualitative.risk_indicators;
if (risk && typeof risk === 'object') {
  const RISK_ORDER = [
    ['communication', 'Communication Risk'],
    ['reliability', 'Reliability Risk'],
    ['customer_facing', 'Customer-Facing Risk'],
    ['decision_making', 'Decision-Making Risk'],
    ['executive_support', 'Executive Support Risk'],
  ];
  lines.push('RISK INDICATORS');
  lines.push('');
  for (const [key, label] of RISK_ORDER) {
    if (risk[key]) lines.push(label + ': ' + risk[key]);
  }
  lines.push('');
}
// NOTES — operational flags rendered readably (omit if empty).
if (sc.qualitative.flags && sc.qualitative.flags.length > 0) {
  lines.push('NOTES');
  lines.push('');
  sc.qualitative.flags.forEach(f => {
    lines.push('⚠ ' + (FLAG_LABELS[f] || f));
  });
  lines.push('');
}
// RECORDING — durable link to the interview audio (omit if absent).
if (sc.recording_url) {
  lines.push('RECORDING');
  lines.push('');
  lines.push(sc.recording_url);
  lines.push('');
}
// SYSTEM ACTION
lines.push('SYSTEM ACTION');
lines.push('');
if (sc.recommendation.action === 'AUTO_ADVANCE') {
  lines.push('Auto-advanced to: ' + sc.recommendation.next_stage);
  if (sc.recommendation.rationale) {
    wrapWithPrefix('Rationale: ', sc.recommendation.rationale, LINE_WIDTH).forEach(l => lines.push(l));
  }
} else if (sc.recommendation.action === 'AUTO_REJECT') {
  lines.push('Auto-rejected. Courtesy rejection email sent to');
  lines.push('candidate at ' + formatTimestamp(sc.generated_at) + '.');
} else if (sc.recommendation.action === 'RECRUITER_REVIEW') {
  lines.push('Held in Interview stage for recruiter review.');
  lines.push('No auto-advance or auto-reject.');
}
lines.push('');
// FOOTER
lines.push(DIVIDER);
lines.push('Generated by SV AI Screening v1.0');
lines.push('Run ID: ' + sc.workflow_run_id);

const rendered = lines.join('\n');
return [{ json: { ...$json, rendered_scorecard_string: rendered } }];

const sc = $json.scorecard;
const dims = sc.scores.dimensions;
const trunc = (s, n) => !s ? '' : (s.length <= n ? s : s.slice(0, n - 1).trimEnd() + '…');
const fmt = (n) => typeof n === 'number' ? n.toFixed(1) : '';
const row = {
  'Candidate ID': sc.candidate.workable_id || '',
  'Job ID': $json.candidate?.job_id || '',
  'Role Type': sc.role.role_code || '',
  'Tier': String(sc.role.tier || ''),
  'Interview Date': sc.generated_at || '',
  'Overall Score (/30)': fmt(sc.scores.overall),
  'Verdict': sc.scores.verdict || '',
  'CEFR': sc.scores.cefr_overall || '',
  'Pronunciation': fmt(dims.pronunciation?.score),
  'Fluency': fmt(dims.fluency?.score),
  'Grammar': fmt(dims.grammar?.score),
  'Vocabulary': fmt(dims.vocabulary?.score),
  'Coherence': fmt(dims.coherence?.score),
  'Comprehension': fmt(dims.comprehension?.score),
  'Strongest Q': sc.qualitative?.strongest_dimension || '',
  'Weakest Q': sc.qualitative?.weakest_dimension || '',
  'Flags': Array.isArray(sc.qualitative?.flags) ? sc.qualitative.flags.join(', ') : '',
  'Claude Note (truncated)': trunc(sc.qualitative?.claude_note || '', 300),
  'Scorecard URL': '',
};
return [{ json: { ...$json, ...row } }];

const ctx = $('Build Sheet Row (19 cols)').item.json;
const dqRationale = '\n\n— DQ rationale: AI screening determined English proficiency below the threshold for this role tier. This decision was based on the AI-scored recording alone and does not reflect overall potential. Candidate may re-apply for future roles.';
const body = (ctx.rendered_scorecard_string || '') + dqRationale;
return [{ json: { ...ctx, fail_comment_body: body, fail_comment_body_json_str: JSON.stringify(body) } }];

// Expand recording.audio_files[] into per-file items so the Speechace loop iterates per file.
const ctx = $json;
const audio_files = (ctx.recording && ctx.recording.audio_files) || [];
if (audio_files.length === 0) return [];
return audio_files.map(af => ({ json: { ...af } }));

// Build a workflow_c_errors row from a Speechace error item.
const ctx = $('Validate Contract 1 Payload').item.json;
const errObj = $json.error || $json;
const reason = String(errObj.message || errObj.code || errObj.statusCode || errObj.status || 'speechace_error').slice(0, 256);
const details = (() => { try { return JSON.stringify(errObj).slice(0, 4000); } catch { return String(errObj).slice(0, 4000); } })();
return [{ json: {
  workflow: 'workflow_c',
  workable_id: ctx.candidate?.workable_id || null,
  session_id: ctx.recording?.session_id || null,
  node_name: 'cSpeechaceMultipart',
  error_reason: reason,
  error_details: details,
  ts: new Date().toISOString(),
} }];

// Build a workflow_c_errors row from an Anthropic error item.
const ctx = $('Validate Contract 1 Payload').item.json;
const errObj = $json.error || $json;
const reason = String(errObj.message || errObj.code || errObj.statusCode || errObj.status || 'anthropic_error').slice(0, 256);
const details = (() => { try { return JSON.stringify(errObj).slice(0, 4000); } catch { return String(errObj).slice(0, 4000); } })();
return [{ json: {
  workflow: 'workflow_c',
  workable_id: ctx.candidate?.workable_id || null,
  session_id: ctx.recording?.session_id || null,
  node_name: 'cClaudeComp',
  error_reason: reason,
  error_details: details,
  ts: new Date().toISOString(),
} }];

// Completeness gate — hold incomplete non-FAIL assessments for recruiter review.
const j = $json;
const sc = j.scorecard;
const COMPLETENESS_EXPECTED = 7;
const COMPLETENESS_MAX_MISSING = 0; // 0 = hold on ANY missing answer (Sean 2026-06-04)
const tmap = j.speechace_transcripts || {};
const missingQ = [];
let answered = 0;
for (let i = 1; i <= COMPLETENESS_EXPECTED; i++) {
  const t = tmap['q' + i];
  if (t && String(t).trim().length > 0) answered++;
  else missingQ.push('Q' + i);
}
const missingCount = Math.max(0, COMPLETENESS_EXPECTED - answered);
const incomplete = missingCount > COMPLETENESS_MAX_MISSING;
let route = j.verdict;
if (incomplete && j.verdict !== 'FAIL') {
  sc.recommendation.action = 'RECRUITER_REVIEW';
  sc.recommendation.next_stage = null;
  sc.recommendation.rationale_short = 'Held for recruiter review — incomplete assessment (' + missingCount + ' of ' + COMPLETENESS_EXPECTED + ' answers missing: ' + missingQ.join(', ') + '). Scored ' + j.verdict + ' (' + sc.scores.overall + '/30) on the answers provided.';
  if (!sc.qualitative.flags.includes('ai_screening_incomplete')) sc.qualitative.flags.push('ai_screening_incomplete');
  route = 'REVIEW';
}
sc.scores.completeness = { expected: COMPLETENESS_EXPECTED, answered_count: answered, missing_count: missingCount, missing_question_ids: missingQ, incomplete };
// route='REVIEW' when held; an IF node ('Incomplete Hold?') after Build Sheet Row branches it to the hold branch.
return [{ json: { ...j, scorecard: sc, route, completeness: sc.scores.completeness } }];
